import{_ as e,c as d,o as t,R as o}from"./chunks/framework.Cfz5bXfs.js";const y=JSON.parse('{"title":"正则表达式","description":"","frontmatter":{},"headers":[],"relativePath":"code/RegularExpression.md","filePath":"code/RegularExpression.md","lastUpdated":1708316038000}'),c={name:"code/RegularExpression.md"},l=o('<h1 id="正则表达式" tabindex="-1">正则表达式 <a class="header-anchor" href="#正则表达式" aria-label="Permalink to &quot;正则表达式&quot;">​</a></h1><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><p>正则表达式<code>Regular Expression</code>是一种文本模式，包括普通字符（例如：<code>a</code> 到 <code>z </code>之间的字母）和特殊字符（称为&quot;元字符&quot;），可以用来描述和匹配字符串的特定模式。</p><p>正则表达式是一种用于模式匹配和搜索文本的工具。</p><p>正则表达式提供了一种灵活且强大的方式来查找、替换、验证和提取文本数据。</p><p>正则表达式可以应用于各种编程语言和文本处理工具中，如 <code>JavaScript</code>、<code>Python</code>、<code>Java</code>、<code>Perl</code> 等。</p><h2 id="模式" tabindex="-1">模式 <a class="header-anchor" href="#模式" aria-label="Permalink to &quot;模式&quot;">​</a></h2><p>正则表达式的模式可以包括以下内容：</p><ul><li>字面值字符：例如字母、数字、空格等，可以直接匹配它们自身。</li><li>特殊字符：例如点号 <code>.</code>、星号 <code>*</code>、加号 <code>+</code>、问号 <code>?</code> 等，它们具有特殊的含义和功能。</li><li>字符类：用方括号 <code>[ ]</code> 包围的字符集合，用于匹配方括号内的任意一个字符。</li><li>元字符：例如 <code>\\d</code>、<code>\\w</code>、<code>\\s</code> 等，用于匹配特定类型的字符，如数字、字母、空白字符等。</li><li>量词：例如 <code>{n}</code>、<code>{n,}</code>、<code>{n,m}</code> 等，用于指定匹配的次数或范围。</li><li>边界符号：例如 <code>^</code>、<code>$</code>、<code>\\b</code>、<code>\\B</code> 等，用于匹配字符串的开头、结尾或单词边界位置。</li></ul><h2 id="元字符和特性" tabindex="-1">元字符和特性 <a class="header-anchor" href="#元字符和特性" aria-label="Permalink to &quot;元字符和特性&quot;">​</a></h2><h3 id="字符匹配" tabindex="-1">字符匹配 <a class="header-anchor" href="#字符匹配" aria-label="Permalink to &quot;字符匹配&quot;">​</a></h3><ul><li>普通字符：普通字符按照字面意义进行匹配，例如匹配字母 <code>a</code> 将匹配到文本中的 <code>a</code> 字符。</li><li>元字符：元字符具有特殊的含义，例如 <code>\\d</code> 匹配任意数字字符，<code>\\w</code> 匹配任意字母数字字符，<code>.</code> 匹配任意字符（除了换行符）等。</li></ul><h3 id="量词" tabindex="-1">量词 <a class="header-anchor" href="#量词" aria-label="Permalink to &quot;量词&quot;">​</a></h3><ul><li><code>*</code>：匹配前面的模式零次或多次。</li><li><code>+</code>：匹配前面的模式一次或多次。</li><li><code>?</code>：匹配前面的模式零次或一次。</li><li><code>{n}</code>：匹配前面的模式恰好 n 次。</li><li><code>{n,}</code>：匹配前面的模式至少 n 次。</li><li><code>{n,m}</code>：匹配前面的模式至少 n 次且不超过 m 次。</li></ul><h3 id="字符类" tabindex="-1">字符类 <a class="header-anchor" href="#字符类" aria-label="Permalink to &quot;字符类&quot;">​</a></h3><ul><li><code>[ ]</code>：匹配括号内的任意一个字符。例如：<code>[abc]</code> 匹配字符 &quot;a&quot;、&quot;b&quot; 或 &quot;c&quot;。</li><li><code>[^ ]</code>：匹配除了括号内的字符以外的任意一个字符。例如：<code>[^abc]</code> 匹配除了字符 &quot;a&quot;、&quot;b&quot; 或 &quot;c&quot; 以外的任意字符。</li></ul><h3 id="边界匹配" tabindex="-1">边界匹配 <a class="header-anchor" href="#边界匹配" aria-label="Permalink to &quot;边界匹配&quot;">​</a></h3><ul><li><code>^</code>：匹配字符串的开头。</li><li><code>$</code>：匹配字符串的结尾。</li><li><code>\\b</code>：匹配单词边界。</li><li><code>\\B</code>：匹配非单词边界。</li></ul><h3 id="分组和捕获" tabindex="-1">分组和捕获 <a class="header-anchor" href="#分组和捕获" aria-label="Permalink to &quot;分组和捕获&quot;">​</a></h3><ul><li><code>( )</code>：用于分组和捕获子表达式。</li><li><code>(?: )</code>：用于分组但不捕获子表达式。</li></ul><h3 id="特殊字符" tabindex="-1">特殊字符 <a class="header-anchor" href="#特殊字符" aria-label="Permalink to &quot;特殊字符&quot;">​</a></h3><ul><li><code>\\</code>：转义字符，用于匹配特殊字符本身。</li><li><code>.</code>：匹配任意字符（除了换行符）。</li><li><code>|</code>：用于指定多个模式的选择。</li></ul><h2 id="语法" tabindex="-1">语法 <a class="header-anchor" href="#语法" aria-label="Permalink to &quot;语法&quot;">​</a></h2><h3 id="普通字符" tabindex="-1">普通字符 <a class="header-anchor" href="#普通字符" aria-label="Permalink to &quot;普通字符&quot;">​</a></h3><table><thead><tr><th><strong>字符</strong></th><th><strong>描述</strong></th><th><strong>实例</strong></th></tr></thead><tbody><tr><td><code>[ABC]</code></td><td>匹配 <code>[...]</code> 中的所有字符。</td><td><code>[aei]</code> 匹配字符串 <code>google runoob taobao</code> 中所有的 <code>e</code> <code>a</code> 字母。</td></tr><tr><td><code>[^ABC]</code></td><td>匹配除了 <code>[...]</code> 中字符的所有字符</td><td></td></tr><tr><td><code>[A-Z]</code></td><td><code>[A-Z]</code> 表示一个区间，匹配所有大写字母。</td><td></td></tr><tr><td><code>[a-z]</code></td><td>表示所有小写字母。</td><td></td></tr><tr><td><code>.</code></td><td>匹配除换行符（<code>\\n</code>、<code>\\r</code>）之外的任何单个字符，相等于 <code>[^\\n\\r]</code>。</td><td></td></tr><tr><td><code>[\\s\\S]</code></td><td>匹配所有。<code>\\s</code> 是匹配所有空白符，包括换行，<code>\\S</code> 非空白符，不包括换行。</td><td></td></tr><tr><td><code>\\w</code></td><td>匹配字母、数字、下划线。等价于 <code>[A-Za-z0-9_]</code></td><td></td></tr><tr><td><code>\\d</code></td><td>匹配任意一个阿拉伯数字（<code>0</code> 到 <code>9</code>）。等价于 <code>[0-9]</code></td><td></td></tr></tbody></table><h3 id="非打印字符" tabindex="-1">非打印字符 <a class="header-anchor" href="#非打印字符" aria-label="Permalink to &quot;非打印字符&quot;">​</a></h3><p>非打印字符也可以是正则表达式的组成部分。下表列出了表示非打印字符的转义序列：</p><table><thead><tr><th style="text-align:left;">字符</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>\\cx</code></td><td style="text-align:left;">匹配由 <code>x</code> 指明的控制字符。例如： <code>\\cM</code> 匹配一个 <code>Control-M</code> 或回车符。<code>x</code> 的值必须为 <code>A-Z</code> 或 <code>a-z</code> 之一。否则，将 <code>c</code> 视为一个原义的 <code>&#39;c&#39;</code> 字符。</td></tr><tr><td style="text-align:left;"><code>\\f</code></td><td style="text-align:left;">匹配一个换页符。等价于<code> \\x0c</code> 和 <code>\\cL</code>。</td></tr><tr><td style="text-align:left;"><code>\\n</code></td><td style="text-align:left;">匹配一个换行符。等价于 <code>\\x0a</code> 和 <code>\\cJ</code>。</td></tr><tr><td style="text-align:left;"><code>\\r</code></td><td style="text-align:left;">匹配一个回车符。等价于 <code>\\x0d</code> 和 <code>\\cM</code>。</td></tr><tr><td style="text-align:left;"><code>\\s</code></td><td style="text-align:left;">匹配任何空白字符，包括空格、制表符、换页符等等。等价于 <code>[ \\f\\n\\r\\t\\v]</code>。注意 <code>Unicode</code> 正则表达式会匹配全角空格符。</td></tr><tr><td style="text-align:left;"><code>\\S</code></td><td style="text-align:left;">匹配任何非空白字符。等价于 <code>[^ \\f\\n\\r\\t\\v]</code>。</td></tr><tr><td style="text-align:left;"><code>\\t</code></td><td style="text-align:left;">匹配一个制表符。等价于 <code>\\x09</code> 和 <code>\\cI</code>。</td></tr><tr><td style="text-align:left;"><code>\\v</code></td><td style="text-align:left;">匹配一个垂直制表符。等价于 <code>\\x0b</code> 和 <code>\\cK</code>。</td></tr></tbody></table><h3 id="特殊字符-1" tabindex="-1">特殊字符 <a class="header-anchor" href="#特殊字符-1" aria-label="Permalink to &quot;特殊字符&quot;">​</a></h3><p>所谓特殊字符，就是一些有特殊含义的字符，如上面说的 <code>runoo\\*b</code> 中的 <code>*</code>，简单的说就是表示任何字符串的意思。如果要查找字符串中的 <code>*</code> 符号，则需要对 <code>*</code> 进行转义，即在其前加一个 <code>\\*</code>，<code>runo\\*ob</code> 匹配字符串 <code>runo\\*ob</code>。</p><p>许多元字符要求在试图匹配它们时特别对待。若要匹配这些特殊字符，必须首先使字符“转义”，即，将反斜杠字符<code>\\*</code>放在它们前面。下表列出了正则表达式中的特殊字符：</p><table><thead><tr><th style="text-align:left;">特别字符</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>$</code></td><td style="text-align:left;">匹配输入字符串的结尾位置。如果设置了 <code>RegExp</code> 对象的 <code>Multiline</code> 属性，则 <code>$</code> 也匹配 <code>\\n</code> 或 <code>\\r</code>。要匹配 <code>$</code> 字符本身，请使用 <code>\\$</code>。</td></tr><tr><td style="text-align:left;"><code>( )</code></td><td style="text-align:left;">标记一个子表达式的开始和结束位置。子表达式可以获取供以后使用。要匹配这些字符，请使用 <code>\\(</code> 和<code> \\)</code>。</td></tr><tr><td style="text-align:left;"><code>*</code></td><td style="text-align:left;">匹配前面的子表达式零次或多次。要匹配 <code>*</code> 字符，请使用 <code>\\*</code>。</td></tr><tr><td style="text-align:left;"><code>+</code></td><td style="text-align:left;">匹配前面的子表达式一次或多次。要匹配 <code>+</code> 字符，请使用 <code>\\+</code>。</td></tr><tr><td style="text-align:left;"><code>.</code></td><td style="text-align:left;">匹配除换行符 <code>\\n</code> 之外的任何单字符。要匹配 <code>.</code> ，请使用 <code>\\.</code> 。</td></tr><tr><td style="text-align:left;"><code>[</code></td><td style="text-align:left;">标记一个中括号表达式的开始。要匹配 <code>[</code>，请使用 <code>\\[</code>。</td></tr><tr><td style="text-align:left;"><code>?</code></td><td style="text-align:left;">匹配前面的子表达式零次或一次，或指明一个非贪婪限定符。要匹配 <code>?</code> 字符，请使用 <code>\\?</code>。</td></tr><tr><td style="text-align:left;"><code>\\</code></td><td style="text-align:left;">将下一个字符标记为或特殊字符、或原义字符、或向后引用、或八进制转义符。例如： <code>n</code> 匹配字符 <code>n</code>。<code>\\n</code> 匹配换行符。序列 <code>\\\\</code> 匹配 <code>\\</code>，而 <code>\\(</code> 则匹配 <code>(</code>。</td></tr><tr><td style="text-align:left;"><code>^</code></td><td style="text-align:left;">匹配输入字符串的开始位置，除非在方括号表达式中使用，当该符号在方括号表达式中使用时，表示不接受该方括号表达式中的字符集合。要匹配 <code>^</code> 字符本身，请使用 <code>\\^</code>。</td></tr><tr><td style="text-align:left;"><code>{</code></td><td style="text-align:left;">标记限定符表达式的开始。要匹配 <code>{</code>，请使用 <code>\\{</code>。</td></tr><tr><td style="text-align:left;">`</td><td style="text-align:left;">`</td></tr></tbody></table><h3 id="限定符" tabindex="-1">限定符 <a class="header-anchor" href="#限定符" aria-label="Permalink to &quot;限定符&quot;">​</a></h3><p>限定符用来指定正则表达式的一个给定组件必须要出现多少次才能满足匹配。有 <code>*</code> 或 <code>+</code> 或 <code>?</code> 或 <code>{n}</code> 或 <code>{n,}</code> 或 <code>{n,m}</code> 共 <code>6</code> 种。</p><p>正则表达式的限定符有：</p><table><thead><tr><th style="text-align:left;">字符</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>*</code></td><td style="text-align:left;">匹配前面的子表达式零次或多次。例如：<code>zo*</code> 能匹配 <code>z</code> 以及 <code>zoo</code>。<code>*</code> 等价于 <code>{0,}</code>。</td></tr><tr><td style="text-align:left;"><code>+</code></td><td style="text-align:left;">匹配前面的子表达式一次或多次。例如：<code>zo+</code> 能匹配 <code>zo</code> 以及 <code>zoo</code>，但不能匹配 <code>z</code>。<code>+</code> 等价于 <code>{1,}</code>。</td></tr><tr><td style="text-align:left;"><code>?</code></td><td style="text-align:left;">匹配前面的子表达式零次或一次。例如：<code>do(es)?</code> 可以匹配 <code>do</code>、 <code>does</code>、 <code>doxy</code> 中的 <code>do</code> 和 <code>does</code>。<code>?</code> 等价于 <code>{0,1}</code>。</td></tr><tr><td style="text-align:left;"><code>{n}</code></td><td style="text-align:left;"><code>n</code> 是一个非负整数。匹配确定的 <code>n</code> 次。例如：<code>o{2}</code> 不能匹配 <code>Bob</code> 中的 <code>o</code>，但是能匹配 <code>food</code> 中的两个 <code>o</code>。</td></tr><tr><td style="text-align:left;"><code>{n,}</code></td><td style="text-align:left;"><code>n</code> 是一个非负整数。至少匹配 <code>n</code> 次。例如：<code>o{2,}</code> 不能匹配 <code>Bob</code> 中的 <code>o</code>，但能匹配 <code>foooood</code> 中的所有 <code>o</code>。<code>o{1,}</code> 等价于 <code>o+</code>。<code>o{0,}</code> 则等价于 <code>o*</code>。</td></tr><tr><td style="text-align:left;"><code>{n,m</code>}</td><td style="text-align:left;"><code>m</code> 和 <code>n</code> 均为非负整数，其中 <code>n &lt;= m</code>。最少匹配 <code>n</code> 次且最多匹配 <code>m</code> 次。例如：<code>o{1,3}</code> 将匹配 <code>fooooood</code> 中的前三个 <code>o</code>。<code>o{0,1}</code> 等价于 <code>o?</code>。请注意在逗号和两个数之间不能有空格。</td></tr></tbody></table><p>以下正则表达式匹配一个正整数，<code>[1-9]</code> 设置第一个数字不是 <code>0</code>，<code>[0-9]*</code> 表示任意多个数字：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>/[1-9][0-9]*/</span></span></code></pre></div><p><code>*</code> 和 <code>+</code> 限定符都是贪婪的，因为它们会尽可能多的匹配文字，只有在它们的后面加上一个 <code>?</code> 就可以实现非贪婪或最小匹配。</p><p>例如：您可能搜索 <code>HTML</code> 文档，以查找在 <code>h1</code> 标签内的内容。<code>HTML</code> 代码如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;h1&gt;RUNOOB-菜鸟教程&lt;/h1&gt;</span></span></code></pre></div><p><strong>贪婪</strong>：下面的表达式匹配从开始小于符号 <code>(&lt;)</code> 到关闭 <code>h1</code> 标记的大于符号 <code>(&gt;)</code> 之间的所有内容。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>/&lt;.*&gt;/</span></span></code></pre></div><p><strong>非贪婪</strong>：如果您只需要匹配开始和结束 <code>h1</code> 标签，下面的非贪婪表达式只匹配 <code>&lt;h1&gt;</code>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>/&lt;.*?&gt;/</span></span></code></pre></div><h3 id="定位符" tabindex="-1">定位符 <a class="header-anchor" href="#定位符" aria-label="Permalink to &quot;定位符&quot;">​</a></h3><p>定位符使您能够将正则表达式固定到行首或行尾。它们还使您能够创建这样的正则表达式，这些正则表达式出现在一个单词内、在一个单词的开头或者一个单词的结尾。</p><p>定位符用来描述字符串或单词的边界，<code>^</code> 和 <code>$</code> 分别指字符串的开始与结束，<code>\\b</code> 描述单词的前或后边界，<code>\\B</code> 表示非单词边界。</p><p>正则表达式的定位符有：</p><table><thead><tr><th style="text-align:left;">字符</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>^</code></td><td style="text-align:left;">匹配输入字符串开始的位置。如果设置了 <code>RegExp</code> 对象的 <code>Multiline</code> 属性，<code>^</code> 还会与 <code>\\n</code> 或 <code>\\r</code> 之后的位置匹配。</td></tr><tr><td style="text-align:left;"><code>$</code></td><td style="text-align:left;">匹配输入字符串结尾的位置。如果设置了 <code>RegExp</code> 对象的 <code>Multiline</code> 属性，<code>$</code> 还会与 <code>\\n</code> 或 <code>\\r</code> 之前的位置匹配。</td></tr><tr><td style="text-align:left;"><code>\\b</code></td><td style="text-align:left;">匹配一个单词边界，即字与空格间的位置。</td></tr><tr><td style="text-align:left;"><code>\\B</code></td><td style="text-align:left;">非单词边界匹配。</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">注意</p><ul><li><p>不能将限定符与定位符一起使用。由于在紧靠换行或者单词边界的前面或后面不能有一个以上位置，因此不允许诸如 <code>^*</code> 之类的表达式。</p></li><li><p>若要匹配一行文本开始处的文本，请在正则表达式的开始使用 <code>^</code> 字符。不要将 <code>^</code> 的这种用法与中括号表达式内的用法混淆。</p></li><li><p>若要匹配一行文本的结束处的文本，请在正则表达式的结束处使用 <code>$</code> 字符。</p></li><li><p>若要在搜索章节标题时使用定位点，下面的正则表达式匹配一个章节标题，该标题只包含两个尾随数字，并且出现在行首。</p></li></ul></div><h3 id="选择" tabindex="-1">选择 <a class="header-anchor" href="#选择" aria-label="Permalink to &quot;选择&quot;">​</a></h3><p>用圆括号 <code>()</code> 将所有选择项括起来，相邻的选择项之间用 <code>|</code> 分隔。</p><p><code>()</code> 表示捕获分组，<code>()</code> 会把每个分组里的匹配的值保存起来， 多个匹配值可以通过数字 <code>n</code> 来查看(<code>n</code> 是一个数字，表示第 <code>n</code> 个捕获组的内容)。</p><h2 id="修饰符-标记" tabindex="-1">修饰符（标记） <a class="header-anchor" href="#修饰符-标记" aria-label="Permalink to &quot;修饰符（标记）&quot;">​</a></h2><blockquote><p>标记也称为修饰符，正则表达式的标记用于指定额外的匹配策略。</p></blockquote><p>标记不写在正则表达式里，标记位于表达式之外，格式如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>/pattern/flags</span></span></code></pre></div><p>下表列出了正则表达式常用的修饰符：</p><table><thead><tr><th style="text-align:left;">修饰符</th><th style="text-align:left;">含义</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>i</code></td><td style="text-align:left;"><code>ignore</code> - 不区分大小写</td><td style="text-align:left;">将匹配设置为不区分大小写，搜索时不区分大小写: <code>A</code> 和 <code>a</code> 没有区别。</td></tr><tr><td style="text-align:left;"><code>g</code></td><td style="text-align:left;"><code>global</code> - 全局匹配</td><td style="text-align:left;">查找所有的匹配项。</td></tr><tr><td style="text-align:left;"><code>m</code></td><td style="text-align:left;"><code>multi line</code> - 多行匹配</td><td style="text-align:left;">使边界字符 <code>^</code> 和 <code>$</code> 匹配每一行的开头和结尾，记住是多行，而不是整个字符串的开头和结尾。</td></tr><tr><td style="text-align:left;"><code>s</code></td><td style="text-align:left;">特殊字符圆点 <code>.</code> 中包含换行符 <code>\\n</code></td><td style="text-align:left;">默认情况下的圆点 <code>.</code> 是匹配除换行符 <code>\\n</code> 之外的任何字符，加上 <code>s</code> 修饰符之后，<code>.</code> 中包含换行符 <code>\\n</code>。</td></tr></tbody></table><h2 id="元字符" tabindex="-1">元字符 <a class="header-anchor" href="#元字符" aria-label="Permalink to &quot;元字符&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">字符</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>\\</code></td><td style="text-align:left;">将下一个字符标记为一个特殊字符、或一个原义字符、或一个 向后引用、或一个八进制转义符。例如：<code>n</code> 匹配字符 <code>n</code>。<code>\\n</code> 匹配一个换行符。序列 <code>\\\\</code> 匹配 <code>\\</code> 而 <code>\\(</code> 则匹配 <code>(</code>。</td></tr><tr><td style="text-align:left;"><code>^</code></td><td style="text-align:left;">匹配输入字符串的开始位置。如果设置了 <code>RegExp</code> 对象的 <code>Multiline</code> 属性，<code>^</code> 也匹配 <code>\\n</code> 或 <code>\\r</code> 之后的位置。</td></tr><tr><td style="text-align:left;"><code>$</code></td><td style="text-align:left;">匹配输入字符串的结束位置。如果设置了 <code>RegExp</code> 对象的 <code>Multiline</code> 属性，<code>$</code> 也匹配 <code>\\n</code> 或 <code>\\r</code> 之前的位置。</td></tr><tr><td style="text-align:left;"><code>*</code></td><td style="text-align:left;">匹配前面的子表达式零次或多次。例如：<code>zo*</code> 能匹配 <code>z</code> 以及 <code>zoo</code>。<code>*</code> 等价于 <code>{0,}</code>。</td></tr><tr><td style="text-align:left;"><code>+</code></td><td style="text-align:left;">匹配前面的子表达式一次或多次。例如：<code>zo+</code> 能匹配 <code>zo</code> 以及 <code>zoo</code>，但不能匹配 <code>z</code>。<code>+</code> 等价于 <code>{1,}</code>。</td></tr><tr><td style="text-align:left;"><code>?</code></td><td style="text-align:left;">匹配前面的子表达式零次或一次。例如：<code>do(es)?</code> 可以匹配 <code>do</code> 或 <code>does</code> 。<code>?</code> 等价于 <code>{0,1}</code>。</td></tr><tr><td style="text-align:left;"><code>{n}</code></td><td style="text-align:left;"><code>n</code> 是一个非负整数。匹配确定的 <code>n</code> 次。例如：<code>o{2}</code> 不能匹配 <code>Bob</code> 中的 <code>o</code>，但是能匹配 <code>food</code> 中的两个 <code>o</code>。</td></tr><tr><td style="text-align:left;"><code>{n,}</code></td><td style="text-align:left;"><code>n</code> 是一个非负整数。至少匹配 <code>n</code> 次。例如：<code>o{2,}</code> 不能匹配 <code>Bob</code> 中的 <code>o</code>，但能匹配 <code>foooood</code> 中的所有 <code>o</code>。<code>o{1,}</code> 等价于 <code>o+</code>。<code>o{0,}</code> 则等价于 <code>o*</code>。</td></tr><tr><td style="text-align:left;"><code>{n,m}</code></td><td style="text-align:left;"><code>m</code> 和 <code>n</code> 均为非负整数，其中 <code>n &lt;= m</code>。最少匹配 <code>n</code> 次且最多匹配 <code>m</code> 次。例如：<code>o{1,3}</code> 将匹配 <code>fooooood</code> 中的前三个 <code>o</code>。<code>o{0,1}</code> 等价于 <code>o?</code>。请注意在逗号和两个数之间不能有空格。</td></tr><tr><td style="text-align:left;"><code>?</code></td><td style="text-align:left;">当该字符紧跟在任何一个其他限制符 <code>(*, +, ?, {n}, {n,}, {n,m})</code> 后面时，匹配模式是非贪婪的。非贪婪模式尽可能少的匹配所搜索的字符串，而默认的贪婪模式则尽可能多的匹配所搜索的字符串。例如：对于字符串 <code>oooo</code>，<code>o+?</code> 将匹配单个 <code>o</code>，而 <code>o+</code> 将匹配所有 <code>o</code>。</td></tr><tr><td style="text-align:left;"><code>.</code></td><td style="text-align:left;">匹配除换行符（<code>\\n</code>、<code>\\r</code>）之外的任何单个字符。</td></tr><tr><td style="text-align:left;"><code>(pattern)</code></td><td style="text-align:left;">匹配 <code>pattern</code> 并获取这一匹配。所获取的匹配可以从产生的 <code>Matches</code> 集合得到，在 <code>VBScript</code> 中使用 <code>SubMatches</code> 集合，在 <code>JScript</code> 中则使用 <code>$0…$9</code> 属性。要匹配圆括号字符，请使用 <code>\\(</code> 或 <code>\\)</code>。</td></tr><tr><td style="text-align:left;"><code>(?:pattern)</code></td><td style="text-align:left;">匹配 <code>pattern</code> 但不获取匹配结果，也就是说这是一个非获取匹配，不进行存储供以后使用。这在使用 &quot;或&quot; 字符来组合一个模式的各个部分是很有用。</td></tr><tr><td style="text-align:left;"><code>(?=pattern)</code></td><td style="text-align:left;">正向肯定预查（<code>look ahead positive assert</code>），在任何匹配 <code>pattern</code> 的字符串开始处匹配查找字符串。这是一个非获取匹配，也就是说，该匹配不需要获取供以后使用。例如：<code>Windows(?=2000)</code> 能匹配 <code>Windows2000</code> 中的 <code>Windows</code>，但不能匹配 <code>Windows3.1</code> 中的 <code>Windows</code>。预查不消耗字符，也就是说，在一个匹配发生后，在最后一次匹配之后立即开始下一次匹配的搜索，而不是从包含预查的字符之后开始。</td></tr><tr><td style="text-align:left;"><code>(?!pattern)</code></td><td style="text-align:left;">正向否定预查(<code>negative assert</code>)，在任何不匹配 <code>pattern</code> 的字符串开始处匹配查找字符串。这是一个非获取匹配，也就是说，该匹配不需要获取供以后使用。例如 <code>Windows(?!2000)</code> 能匹配 <code>Windows3.1</code> 中的 <code>Windows</code>，但不能匹配 <code>Windows2000</code> 中的 <code>Windows</code>。预查不消耗字符，也就是说，在一个匹配发生后，在最后一次匹配之后立即开始下一次匹配的搜索，而不是从包含预查的字符之后开始。</td></tr><tr><td style="text-align:left;"><code>(?&lt;=pattern)</code></td><td style="text-align:left;">反向(<code>look behind</code>)肯定预查，与正向肯定预查类似，只是方向相反。例如：&quot;<code>(?&lt;=2000)Windows</code>&quot;能匹配&quot;<code>2000Windows</code>&quot;中的&quot;<code>Windows</code>&quot;，但不能匹配&quot;<code>3.1Windows</code>&quot;中的&quot;<code>Windows</code>&quot;。</td></tr><tr><td style="text-align:left;"><code>(?&lt;!pattern)</code></td><td style="text-align:left;">反向否定预查，与正向否定预查类似，只是方向相反。例如&quot;<code>(?&lt;!2000)Windows</code>&quot;能匹配&quot;<code>3.1Windows</code>&quot;中的&quot;<code>Windows</code>&quot;，但不能匹配&quot;<code>2000Windows</code>&quot;中的&quot;<code>Windows</code>&quot;。</td></tr><tr><td style="text-align:left;"><code>[xyz]</code></td><td style="text-align:left;">字符集合。匹配所包含的任意一个字符。例如： <code>[abc]</code> 可以匹配 <code>plain</code> 中的 <code>a</code>。</td></tr><tr><td style="text-align:left;"><code>[^xyz]</code></td><td style="text-align:left;">负值字符集合。匹配未包含的任意字符。例如： <code>[^abc]</code> 可以匹配 <code>plain</code> 中的 <code>p</code>、<code>l</code>、<code>i</code>、<code>n</code>。</td></tr><tr><td style="text-align:left;"><code>[a-z]</code></td><td style="text-align:left;">字符范围。匹配指定范围内的任意字符。例如：<code>[a-z]</code> 可以匹配 <code>a</code> 到 <code>z</code> 范围内的任意小写字母字符。</td></tr><tr><td style="text-align:left;"><code>[^a-z]</code></td><td style="text-align:left;">负值字符范围。匹配任何不在指定范围内的任意字符。例如：<code>[^a-z]</code> 可以匹配任何不在 <code>a</code> 到 <code>z</code> 范围内的任意字符。</td></tr><tr><td style="text-align:left;"><code>\\b</code></td><td style="text-align:left;">匹配一个单词边界，也就是指单词和空格间的位置。例如： <code>er\\b</code> 可以匹配 <code>never</code> 中的 <code>er</code>，但不能匹配 <code>verb</code> 中的 <code>er</code>。</td></tr><tr><td style="text-align:left;"><code>\\B</code></td><td style="text-align:left;">匹配非单词边界。<code>er\\B</code> 能匹配 <code>verb</code> 中的 <code>er</code>，但不能匹配 <code>never</code> 中的 <code>er</code>。</td></tr><tr><td style="text-align:left;"><code>\\cx</code></td><td style="text-align:left;">匹配由 <code>x</code> 指明的控制字符。例如： <code>\\cM</code> 匹配一个 <code>Control-M</code> 或回车符。<code>x</code> 的值必须为 <code>A-Z</code> 或 <code>a-z</code> 之一。否则，将 <code>c</code> 视为一个原义的 <code>c</code> 字符。</td></tr><tr><td style="text-align:left;"><code>\\d</code></td><td style="text-align:left;">匹配一个数字字符。等价于 <code>[0-9]</code>。</td></tr><tr><td style="text-align:left;"><code>\\D</code></td><td style="text-align:left;">匹配一个非数字字符。等价于 <code>[^0-9]</code>。</td></tr><tr><td style="text-align:left;"><code>\\f</code></td><td style="text-align:left;">匹配一个换页符。等价于 <code>\\x0c</code> 和 <code>\\cL</code>。</td></tr><tr><td style="text-align:left;"><code>\\n</code></td><td style="text-align:left;">匹配一个换行符。等价于 <code>\\x0a</code> 和 <code>\\cJ</code>。</td></tr><tr><td style="text-align:left;"><code>\\r</code></td><td style="text-align:left;">匹配一个回车符。等价于 <code>\\x0d</code> 和 <code>\\cM</code>。</td></tr><tr><td style="text-align:left;"><code>\\s</code></td><td style="text-align:left;">匹配任何空白字符，包括空格、制表符、换页符等等。等价于 <code>[ \\f\\n\\r\\t\\v]</code>。</td></tr><tr><td style="text-align:left;"><code>\\S</code></td><td style="text-align:left;">匹配任何非空白字符。等价于 <code>[^ \\f\\n\\r\\t\\v]</code>。</td></tr><tr><td style="text-align:left;"><code>\\t</code></td><td style="text-align:left;">匹配一个制表符。等价于 <code>\\x09</code> 和 <code>\\cI</code>。</td></tr><tr><td style="text-align:left;"><code>\\v</code></td><td style="text-align:left;">匹配一个垂直制表符。等价于 <code>\\x0b</code> 和 <code>\\cK</code>。</td></tr><tr><td style="text-align:left;"><code>\\w</code></td><td style="text-align:left;">匹配字母、数字、下划线。等价于 <code>[A-Za-z0-9_]</code>。</td></tr><tr><td style="text-align:left;"><code>\\W</code></td><td style="text-align:left;">匹配非字母、数字、下划线。等价于 <code>[^A-Za-z0-9_]</code>。</td></tr><tr><td style="text-align:left;"><code>\\xn</code></td><td style="text-align:left;">匹配 <code>n</code>，其中 <code>n</code> 为十六进制转义值。十六进制转义值必须为确定的两个数字长。例如：<code>\\x41</code> 匹配 <code>A</code>。<code>\\x041</code> 则等价于 <code>\\x04</code> &amp; <code>1</code>。正则表达式中可以使用 <code>ASCII</code> 编码。</td></tr><tr><td style="text-align:left;"><code>\\num</code></td><td style="text-align:left;">匹配 <code>num</code>，其中 <code>num</code> 是一个正整数。对所获取的匹配的引用。例如：<code>(.)\\1</code> 匹配两个连续的相同字符。</td></tr><tr><td style="text-align:left;"><code>\\n</code></td><td style="text-align:left;">标识一个八进制转义值或一个向后引用。如果 <code>\\n</code> 之前至少 <code>n</code> 个获取的子表达式，则 <code>n</code> 为向后引用。否则，如果 <code>n</code> 为八进制数字 <code>(0-7)</code>，则 <code>n</code> 为一个八进制转义值。</td></tr><tr><td style="text-align:left;"><code>\\nm</code></td><td style="text-align:left;">标识一个八进制转义值或一个向后引用。如果 <code>\\nm</code> 之前至少有 <code>nm</code> 个获得子表达式，则 <code>nm</code> 为向后引用。如果 <code>\\nm</code> 之前至少有 <code>n</code> 个获取，则 <code>n</code> 为一个后跟文字 <code>m</code> 的向后引用。如果前面的条件都不满足，若 <code>n</code> 和 <code>m</code> 均为八进制数字 <code>(0-7)</code>，则 <code>\\nm</code> 将匹配八进制转义值 <code>nm</code>。</td></tr><tr><td style="text-align:left;"><code>\\nml</code></td><td style="text-align:left;">如果 <code>n</code> 为八进制数字 <code>(0-3)</code>，且 <code>m</code> 和 <code>l</code> 均为八进制数字 (0-7)，则匹配八进制转义值 <code>nml</code>。</td></tr><tr><td style="text-align:left;"><code>\\un</code></td><td style="text-align:left;">匹配 <code>n</code>，其中 <code>n</code> 是一个用四个十六进制数字表示的 <code>Unicode</code> 字符。</td></tr></tbody></table><h2 id="优先级" tabindex="-1">优先级 <a class="header-anchor" href="#优先级" aria-label="Permalink to &quot;优先级&quot;">​</a></h2><p>以下是一些常见正则表达式运算符按照优先级从高到低的顺序：</p><ul><li><p><strong>转义符号：</strong> <code>\\</code> 是用于转义其他特殊字符的转义符号。它具有最高的优先级。</p><p>示例：<code>\\d</code>、<code>\\.</code> 等，其中 <code>\\d</code> 匹配数字，<code>\\.</code> 匹配点号。</p></li><li><p><strong>括号：</strong> 圆括号 <code>()</code> 用于创建子表达式，具有高于其他运算符的优先级。</p><p>示例：<code>(abc)+</code> 匹配 <code>abc</code> 一次或多次。</p></li><li><p><strong>量词：</strong> 量词指定前面的元素可以重复的次数。</p><p>示例：<code>a*</code> 匹配零个或多个 <code>a</code>。</p></li><li><p><strong>字符类：</strong> 字符类使用方括号 <code>[]</code> 表示，用于匹配括号内的任意字符。</p><p>示例：<code>[aeiou]</code> 匹配任何一个元音字母。</p></li><li><p><strong>断言：</strong> 断言是用于检查字符串中特定位置的条件的元素。</p><p>示例：<code>^</code> 表示行的开头，<code>$</code> 表示行的结尾。</p></li><li><p><strong>连接：</strong> 连接在没有其他运算符的情况下表示字符之间的简单连接。</p><p>示例：<code>abc</code> 匹配 <code>abc</code>。</p></li><li><p><strong>管道：</strong> 管道符号 <code>|</code> 表示“或”关系，用于在多个模式之间选择一个。</p><p>示例：<code>cat|dog</code> 匹配 <code>cat</code> 或 <code>dog</code>。</p></li></ul>',65),a=[l];function n(i,s,r,g,x,f){return t(),d("div",null,a)}const p=e(c,[["render",n]]);export{y as __pageData,p as default};
